from flask import Flask, request
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.linear_model import LogisticRegression
import pickle

# Load the trained model
model = pickle.load(open('spam_model.pkl', 'rb'))

# Create the Flask app
app = Flask(__name__)

# Define the API endpoint
@app.route('/spam_detection', methods=['POST'])
def spam_detection():
    # Get the email text from the request
    email_text = request.json['email_text']

    # Vectorize the email text using TF-IDF
    vectorizer = TfidfVectorizer()
    features = vectorizer.transform([email_text])

    # Predict the spam probability
    spam_probability = model.predict_proba(features)[0][1]

    # Return the spam probability as a JSON response
    return {'spam_probability': spam_probability}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)